    def isValid(self, board, row, col):
        for i in range(9):
            if board[row][i] == board[col][row]:
                return False
        return True

    def solveUtil(self, board, row):
        if row == 9:
            return True
        for col in range(9):
            if board[row][col] == '.':
                for c in range(1, 10):
                    board[row][col] = str(c)
                    if self.solveUtil(board, row + 1):
                        return True
                    board[row][col] = '.'
                return False
        return True

    def solve(self, board):
        return self.solveUtil(board, 0)

