#include <iostream>
#include <vector>
#include <string>
using namespace std;

void readBoard(vector<string>& board, int& N) {
    cin >> N;
    for (int i = 0; i < 9; i++) {
        string row;
        cin >> row;
        board.push_back(row);
    }
}

bool isValid(vector<string>& board, int row, int col) {
    for (int i = 0; i < 9; i++) {
        if (board[row][i] == board[col][row]) {
            return false;
        }
    }
    return true;
}

void printBoard(const vector<string>& board) {
    for (const auto& row : board) {
        cout << row << endl;
    }
}

class Solution {
public:
bool solve(vector<string>& board) {
    for (int i = 0; i < 9; i++) {
        for (int j = 0; j < 9; j++) {
            if (board[i][j] == '.') {
                for (char c = '1'; c <= '9'; c++) {
                    board[i][j] = c;
                    if (solve(board)) {
                        return true;
                    }
                    board[i][j] = '.';
                }
                return false;
            }
        }
    }
    return true;
}
};

int main() {
    Solution solution;
    int N;
    vector<string> board;
    readBoard(board, N);
    solution.solve(board);
    printBoard(board);
    return 0;
}
